using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using Newtonsoft.Json;
using Newtonsoft.Json.Linq;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.Text;

namespace UnityConstantsGenerator
{
    [Generator]
    public class UnityConstantsGenerator : ISourceGenerator
    {
        public void Initialize(GeneratorInitializationContext context)
        {
            // No initialization required
        }

        public void Execute(GeneratorExecutionContext context)
        {
            // 1. Try to find the file from AdditionalFiles (Standard Roslyn Way)
            var configFile = context.AdditionalFiles.FirstOrDefault(f => f.Path.EndsWith("config.json", StringComparison.OrdinalIgnoreCase));
            string jsonText = null;
            string sourceMethod = "";

            if (configFile != null)
            {
                jsonText = configFile.GetText(context.CancellationToken)?.ToString();
                sourceMethod = $"AdditionalFiles: {configFile.Path}";
            }
            
            // 2. Fallback: Search for Assets/config.json in the current directory (Unity specific helper)
            if (string.IsNullOrEmpty(jsonText))
            {
                string fallbackPath = Path.Combine(Directory.GetCurrentDirectory(), "Assets", "config.json");
                if (File.Exists(fallbackPath))
                {
                    jsonText = File.ReadAllText(fallbackPath);
                    sourceMethod = $"Fallback (File.ReadAllText): {fallbackPath}";
                }
            }

            if (string.IsNullOrEmpty(jsonText)) return;

            try
            {
                var jObject = JObject.Parse(jsonText);
                var dict = new Dictionary<string, string>();
                ParseJToken(jObject, "", dict);

                var sb = new StringBuilder();
                sb.AppendLine("// <auto-generated />");
                sb.AppendLine($"// Generated from: {sourceMethod}");
                sb.AppendLine("namespace UnityConstant");
                sb.AppendLine("{");
                sb.AppendLine("    public static class Config");
                sb.AppendLine("    {");

                foreach (var kvp in dict)
                {
                    sb.AppendLine($"        public const string {kvp.Key} = \"{kvp.Value}\";");
                }

                sb.AppendLine("    }");
                sb.AppendLine("}");

                context.AddSource("UnityConstant_Config_Generator.g.cs", SourceText.From(sb.ToString(), Encoding.UTF8));
            }
            catch (Exception ex)
            {
                // Source generators should fail silently or report diagnostics
                // Optional: add a source file with the error comment for debugging
                context.AddSource("UnityConstant_Config_Generator_Error.g.cs", $"/* error: {ex.Message} */");
            }
        }

        private void ParseJToken(JToken token, string prefix, Dictionary<string, string> dict)
        {
            switch (token.Type)
            {
                case JTokenType.Object:
                    foreach (var prop in token.Children<JProperty>())
                    {
                        var newPrefix = string.IsNullOrEmpty(prefix) ? prop.Name : $"{prefix}_{prop.Name}";
                        ParseJToken(prop.Value, newPrefix, dict);
                    }
                    break;
                case JTokenType.Array:
                    int i = 0;
                    foreach (var item in token.Children())
                    {
                        ParseJToken(item, $"{prefix}_{i++}", dict);
                    }
                    break;
                default:
                    dict[prefix] = token.ToString();
                    break;
            }
        }
    }
}
